#include<bits/stdc++.h>
using namespace std;
int n,a[1010];
int main()
{
	int t;
	scanf("%d",&t);
	while(t--)
	{
		scanf("%d",&n);
		for(int i=1;i<=n;i++)
		{
			scanf("%d",&a[i]);
		}
		for(int i=n;i>=1;i--)
		{
			a[i]=a[i]-a[i-1];
		}
		reverse(a+1,a+1+n);
		int sum=0;
		for(int i=1;i<=n;i+=2)
		{
			sum^=a[i];
		}
		if(sum!=0)
		{
			printf("TAK\n");
		}
		else
		{
			printf("NIE\n");
		}
	}
	return 0;
}
